  function playErrorToastSound() {
    try {
      const now = Date.now();
      const last = Number(window.__LAST_ERROR_TOAST_SOUND_AT__ || 0);
      if (last && (now - last) < 180) return;
      window.__LAST_ERROR_TOAST_SOUND_AT__ = now;
      let audio = window.__ERROR_TOAST_AUDIO__;
      if (!audio) {
        audio = new Audio("https://image2url.com/r2/default/audio/1775222006071-0c6196c2-357e-4a1c-9499-a3ada1f41078.mp3");
        audio.preload = "auto";
        audio.volume = 0.95;
        window.__ERROR_TOAST_AUDIO__ = audio;
      }
      try { audio.currentTime = 0; } catch (_) {}
      const playPromise = audio.play();
      if (playPromise && typeof playPromise.catch === "function") {
        playPromise.catch(() => {});
      }
    } catch (_) {}
  }
  try {
    if (typeof window.__playErrorToastSound !== "function") {
      window.__playErrorToastSound = playErrorToastSound;
    }
  } catch (_) {}

  function showToast(message, type = "info", timeout = 4000, opts = null) {
    try {
      if (type && typeof type === "object") {
        opts = type;
        type = opts.type || "info";
        timeout = opts.timeout != null ? opts.timeout : 4000;
      } else if (timeout && typeof timeout === "object") {
        opts = timeout;
        timeout = opts.timeout != null ? opts.timeout : 4000;
      }
      const options = (opts && typeof opts === "object") ? opts : {};
      if (!dom.toast || !dom.toastMessage) return alert(message);

      const allowedTypes = new Set(["success", "info", "warning", "error"]);
      const variant = allowedTypes.has(String(type || "").toLowerCase()) ? String(type).toLowerCase() : "info";

      const text = (message == null) ? "" : String(message);
      dom.toastMessage.textContent = text;

      dom.toast.classList.remove(
        "app-toast--success",
        "app-toast--info",
        "app-toast--warning",
        "app-toast--error",
        "toast-center",
        "toast-compact",
        "is-visible"
      );
      dom.toast.classList.add("app-toast", "app-toast--" + variant);

      if (options.center === true) {
        dom.toast.classList.add("toast-center");
      }
      if (options.small === true || options.compact === true) {
        dom.toast.classList.add("toast-compact");
      }

      if (options.bg || options.backgroundColor) {
        dom.toast.style.backgroundColor = String(options.bg || options.backgroundColor);
      } else {
        dom.toast.style.removeProperty("background-color");
      }

      if (options.color) {
        dom.toast.style.color = String(options.color);
      } else {
        dom.toast.style.removeProperty("color");
      }

      if (variant === "error") {
        try {
          if (typeof window.__playErrorToastSound === "function") {
            window.__playErrorToastSound();
          } else {
            const now = Date.now();
            const last = Number(window.__LAST_ERROR_TOAST_SOUND_AT__ || 0);
            if (!last || (now - last) > 180) {
              window.__LAST_ERROR_TOAST_SOUND_AT__ = now;
              let audio = window.__ERROR_TOAST_AUDIO__;
              if (!audio) {
                audio = new Audio("https://image2url.com/r2/default/audio/1775222006071-0c6196c2-357e-4a1c-9499-a3ada1f41078.mp3");
                audio.preload = "auto";
                audio.volume = 0.95;
                window.__ERROR_TOAST_AUDIO__ = audio;
              }
              try { audio.currentTime = 0; } catch (_) {}
              const playPromise = audio.play();
              if (playPromise && typeof playPromise.catch === "function") {
                playPromise.catch(() => {});
              }
            }
          }
        } catch (_) {}
      }

      dom.toast.style.visibility = "visible";
      dom.toast.style.opacity = "";
      clearTimeout(showToast._timer);
      clearTimeout(showToast._hideTimer);
      requestAnimationFrame(() => {
        try { dom.toast.classList.add("is-visible"); } catch (_) {}
      });

      const finalTimeout = Math.max(500, Number(options.timeout ?? timeout) || 4000);
      showToast._timer = setTimeout(() => {
        dom.toast.classList.remove("is-visible");
        showToast._hideTimer = setTimeout(() => {
          if (!dom.toast.classList.contains("is-visible")) {
            dom.toast.style.visibility = "hidden";
          }
        }, 240);
      }, finalTimeout);
    } catch (_) {
      alert(message);
    }
  }

  function redirectToLoginImmediately() {
    try {
      const currentHash = String(location.hash || "").toLowerCase();
      if (/^#\/(?:privacy|terms)(?:\/|$)/i.test(currentHash)) return;
    } catch (_) {}
    try {
      const nextUrl = new URL(window.location.href);
      nextUrl.hash = "#/login";
      window.location.replace(nextUrl.toString());
      return;
    } catch (_) {}
    try { window.location.replace("index.html#/login"); return; } catch (_) {}
    try { location.hash = "#/login"; } catch (_) {}
  }
  try { window.__redirectToLoginImmediately = redirectToLoginImmediately; } catch (_) {}

  function formatProviderValue(value) {
    if (value == null) return "";
    if (Array.isArray(value)) {
      return value.map((item) => {
        if (item == null) return "";
        if (typeof item === "object") return JSON.stringify(item);
        return String(item);
      }).filter(Boolean).join("\n");
    }
    if (typeof value === "object") {
      try { return JSON.stringify(value, null, 2); } catch (_) { return String(value); }
    }
    return String(value);
  }

  function flattenProviderCodeValues(value) {
    if (value == null) return [];
    if (Array.isArray(value)) {
      const out = [];
      value.forEach((entry) => {
        out.push(...flattenProviderCodeValues(entry));
      });
      return out;
    }
    if (typeof value === "object") {
      const formatted = formatProviderValue(value).trim();
      return formatted ? [formatted] : [];
    }
    const text = String(value).trim();
    if (!text) return [];
    const lines = text.split(/\r?\n+/).map((entry) => String(entry || "").trim()).filter(Boolean);
    return lines.length > 1 ? lines : [text];
  }

  function dedupeProviderCodeEntries(entries) {
    const out = [];
    const seen = new Set();
    (Array.isArray(entries) ? entries : []).forEach((entry) => {
      const label = String(entry && entry.label || "").trim() || "الكود";
      const value = String(entry && entry.value || "").trim();
      if (!value) return;
      const key = value.toLowerCase();
      if (seen.has(key)) return;
      seen.add(key);
      out.push({ label, value });
    });
    return out;
  }

  function extractProviderField(result, key) {
    if (!result || typeof result !== "object") return null;
    const sources = [
      result,
      result.providerResponse,
      result.provider_response,
      result.responseData,
      result.data,
      result.result,
      result.payload
    ];
    for (let i = 0; i < sources.length; i += 1) {
      const src = sources[i];
      if (!src || typeof src !== "object") continue;
      if (Object.prototype.hasOwnProperty.call(src, key)) return src[key];
      const nested = (src.data && typeof src.data === "object") ? src.data : null;
      if (nested && Object.prototype.hasOwnProperty.call(nested, key)) return nested[key];
      if (nested && nested.order && typeof nested.order === "object" && Object.prototype.hasOwnProperty.call(nested.order, key)) {
        return nested.order[key];
      }
      const order = (src.order && typeof src.order === "object") ? src.order : null;
      if (order && Object.prototype.hasOwnProperty.call(order, key)) return order[key];
    }
    return null;
  }

  function extractProviderPayload(result) {
    if (!result || typeof result !== "object") return null;
    const direct = result.providerResponse || result.provider_response || result.data || result.result || result.payload;
    if (direct && typeof direct === "object") return direct;
    const omit = new Set([
      "success","ok","error","code","message","details","orderCode","order_code","orderId","order_id",
      "reviewForward","review_forward","reviewReason","review_reason","providerErrors","providerBase",
      "total","currency","offers","breakdown","authkey","useruid","uid","sessionKey","session_key","ttlSeconds",
      "source","game","gameSlug","response","note"
    ]);
    const cleaned = {};
    Object.keys(result).forEach((key) => {
      if (omit.has(key)) return;
      cleaned[key] = result[key];
    });
    return Object.keys(cleaned).length ? cleaned : null;
  }

  function extractCodeEntries(payload) {
    if (!payload || typeof payload !== "object") return [];
    const responseValue =
      extractProviderField(payload, "response") ??
      extractProviderField(payload, "note");
    const responseValues = flattenProviderCodeValues(responseValue);
    if (responseValues.length) {
      return dedupeProviderCodeEntries(
        responseValues.map((value) => ({ label: "الكود", value }))
      );
    }
    const source = (payload.data && typeof payload.data === "object") ? payload.data : payload;
    const fields = [
      ["code", "الكود"],
      ["codes", "الكود"],
      ["replay_api", "الكود"],
      ["pin", "PIN"],
      ["pins", "PINs"],
      ["serial", "Serial"],
      ["serials", "Serials"],
      ["voucher", "Voucher"],
      ["vouchers", "Vouchers"],
      ["activationCode", "رمز التفعيل"],
      ["activation_code", "رمز التفعيل"],
      ["redeemCode", "رمز الاسترداد"],
      ["redeem_code", "رمز الاسترداد"],
      ["token", "Token"],
      ["tokens", "Tokens"]
    ];
    const entries = [];
    fields.forEach(([key, label]) => {
      if (!Object.prototype.hasOwnProperty.call(source, key)) return;
      const values = flattenProviderCodeValues(source[key]);
      if (!values.length) return;
      if (key === "message" && entries.length) return;
      values.forEach((value) => {
        entries.push({ label, value });
      });
    });
    return dedupeProviderCodeEntries(entries);
  }

  function copyTextToClipboard(text) {
    if (!text) return Promise.reject(new Error("empty"));
    if (navigator.clipboard && navigator.clipboard.writeText) {
      return navigator.clipboard.writeText(text);
    }
    return new Promise((resolve, reject) => {
      try {
        const ta = document.createElement("textarea");
        ta.value = text;
        ta.style.position = "fixed";
        ta.style.top = "-9999px";
        document.body.appendChild(ta);
        ta.select();
        const ok = document.execCommand("copy");
        document.body.removeChild(ta);
        return ok ? resolve() : reject(new Error("copy_failed"));
      } catch (err) {
        reject(err);
      }
    });
  }

  function extractSuccessResponseText(payload) {
    const entries = extractCodeEntries(payload);
    const direct = entries
      .map((entry) => String(entry && entry.value || "").trim())
      .filter(Boolean);
    if (direct.length) return Array.from(new Set(direct)).join("\n").trim();
    const responseValue =
      extractProviderField(payload, "response") ??
      extractProviderField(payload, "note");
    return flattenProviderCodeValues(responseValue).join("\n").trim();
  }

  function formatSuccessChargeText(total, currency = "") {
    const symbolMap = {
      USD: "$",
      JOD: "د.أ",
      SAR: "ر.س",
      EGP: "ج.م"
    };
    const amount = Number(total);
    const rawCurrency = String(currency || "").trim();
    const currencyKey = rawCurrency.toUpperCase();
    const currencyText = symbolMap[currencyKey] || rawCurrency;
    if (Number.isFinite(amount)) {
      const suffix = currencyText ? String(currencyText).trim() : "";
      return `${amount.toFixed(3)}${suffix}`.trim();
    }
    const rawAmount = String(total == null ? "" : total).trim();
    if (rawAmount) return rawAmount.slice(0, 14);
    return currencyText || "$";
  }

