      banner.style.opacity = "0";
      wrap.style.transform = "translateY(20px) scale(.985)";
      wrap.style.opacity = "0";
      if (hero && typeof hero.__stop === "function") hero.__stop();
      overlayExitTimer = setTimeout(finalizeOverlayClose, CLOSE_ANIM_MS);
