  function normalizeCatalogCurrencyCode(value, rates) {
    const raw = String(value || "").trim();
    if (!raw) return "";
    const upper = raw.toUpperCase();
    if (!rates) return upper;
    if (rates[raw]) return raw;
    if (rates[upper]) return upper;
    let firstCodeKey = "";
    for (const key of Object.keys(rates || {})) {
      const entry = rates[key];
      if (!entry || typeof entry !== "object") continue;
      const id = String(entry.id || entry.currencyId || "").trim();
      if (id && id === raw) return key;
      const code = String(entry.code || "").trim().toUpperCase();
      if (code && code === upper) {
        const isBaseUsd = upper === "USD" && (id === "1" || String(key) === "1");
        if (isBaseUsd) return key;
        if (!firstCodeKey) firstCodeKey = key;
      }
      const symbol = String(entry.symbol || "").trim();
      if (symbol && symbol === raw) return key;
    }
    return firstCodeKey || upper;
  }

  function convertCatalogCurrencyAmount(amount, fromCode, toCode, rates, baseCode) {
    const n = Number(amount);
    if (!Number.isFinite(n)) return null;
    if (!fromCode || !toCode || fromCode === toCode || !rates) return n;
    const base = normalizeCatalogCurrencyCode(baseCode, rates) || "USD";
    const fromRate = fromCode === base ? 1 : Number(rates[fromCode]?.rate);
    const toRate = toCode === base ? 1 : Number(rates[toCode]?.rate);
    if (!Number.isFinite(fromRate) || fromRate <= 0 || !Number.isFinite(toRate) || toRate <= 0) return n;
    const baseAmount = fromCode === base ? n : (n / fromRate);
    return toCode === base ? baseAmount : (baseAmount * toRate);
  }

