    const rates = ctx.rates || null;
    const sourceCode = normalizeCatalogCurrencyCode(currency || state.currency || "USD", rates) || "USD";
    const selectedCode = normalizeCatalogCurrencyCode(ctx.selected || sourceCode, rates) || sourceCode;
    const converted = convertCatalogCurrencyAmount(amount, sourceCode, selectedCode, rates, ctx.base || "USD");
    const displayAmount = Number.isFinite(Number(converted)) ? Number(converted) : amount;
    const symbol = getCatalogCurrencySymbol(selectedCode, rates);
