            var buffer = new ArrayBuffer(8);
            var view = new DataView(buffer);
            view.setUint32(0, 0, false);
            view.setUint32(4, counter, false);
            cryptoObj.subtle.importKey("raw", keyData, { name: "HMAC", hash: "SHA-1" }, false, ["sign"])
