            '.agents-card-copy{min-width:0;display:grid;gap:6px;text-align:start;}',
            '.agents-card-name{min-width:0;font-size:1.05rem;font-weight:900;color:var(--agents-text);unicode-bidi:plaintext;text-align:start;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;}',
            '.agents-card-summary{min-width:0;font-size:.9rem;font-weight:700;color:var(--agents-muted);line-height:1.8;display:-webkit-box;-webkit-box-orient:vertical;-webkit-line-clamp:2;white-space:normal;overflow:hidden;text-align:start;}',
            '.agents-card-body{padding:0 18px 18px;}',
            '.agents-card-divider{height:1px;background:var(--agents-divider);margin-bottom:16px;}',
