          if (!match) match = text.match(/^(\d+(?:\.\d+)?)\s*(?:\u062C\u0648\u0627\u0647\u0631|\u062C\u0648\u0647\u0631\u0629)$/);
          if (match) return `${match[1]} ${gemUnit(match[1])}`;
