          if (normalized.includes("\u0627\u0646\u062A\u0631\u0646\u062A") || normalized.includes("internet")) return "catalog.category.internet";
          if (normalized.includes("\u0627\u0634\u062A\u0631\u0627\u0643") || normalized.includes("subscription")) return "catalog.category.subscriptions";
          if (normalized.includes("\u0639\u0645\u0644\u0627\u062A") || normalized === "currencies" || normalized === "currency") return "catalog.category.currencies";
          if (normalized.includes("\u0648\u062D\u062F\u0627\u062A") || normalized.includes("topup")) return "catalog.category.topups";
          if (normalized.includes("\u0645\u062A\u0646\u0648\u0639") || normalized === "misc") return "catalog.category.misc";
